const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const BUILDING_BLOCK_PREMIUM = 60;
const BUILDING_BLOCK_SIZE = 3;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

export function processScenario(scenario: Scenario): ScenarioOutput {
  const step = scenario.steps[0];
  let basePremium = 0;

  const typeCounts: Record<string, number> = {};
  for (const item of step.items) {
    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
  }

  for (const [type, count] of Object.entries(typeCounts)) {
    if (count === BUILDING_BLOCK_SIZE) {
      basePremium += BUILDING_BLOCK_PREMIUM;
    } else {
      basePremium += BASE_PREMIUMS[type] * count;
    }
  }

  const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
  return { results: [{ premium }] };
}

